const rows = $input.all().map(item => item.json);

if (rows.length === 0) {
  return [{ json: { ok: false, error: 'Encuesta no encontrada', surveyId: null } }];
}

const survey = {
  Encuestaid:    String(rows[0].survey_id),
  NombreEncuesta: rows[0].survey_name,
  Preguntas:     [],
};

const questionsMap = new Map();

for (const row of rows) {
  if (!questionsMap.has(row.question_id)) {
    questionsMap.set(row.question_id, {
      Preguntaid:    String(row.question_id),
      PreguntaTexto: row.question_text,
      PreguntaTipo:  row.question_type,
      obligatorio:   row.is_required,
      opciones:      [],
    });
  }

  if (row.option_id !== null && row.option_id !== undefined) {
    questionsMap.get(row.question_id).opciones.push({
      opcionid:    String(row.option_id),
      opciontexto: row.option_text,
    });
  }
}

survey.Preguntas = Array.from(questionsMap.values());

return [{ json: survey }];
